export type ResizeDir = 'left' | 'right';

export interface ResizeRange {
  start: number;
  end: number;
}

interface GroupChildBoundaryResizeArgs {
  dir: ResizeDir;
  dragged: ResizeRange;
  adjacent: ResizeRange;
  proposedBoundary: number;
  minimumDuration: number;
}

interface GroupEdgeResizeArgs {
  dir: ResizeDir;
  initial: ResizeRange;
  proposedBoundary: number;
  minimumDuration: number;
  minimumStart?: number;
}

interface GroupChildBoundaryResizeResult {
  boundary: number;
  wasClamped: boolean;
  dragged: ResizeRange;
  adjacent: ResizeRange;
}

interface GroupEdgeResizeResult extends ResizeRange {
  boundary: number;
  wasClamped: boolean;
}

const clamp = (value: number, min: number, max: number): number => Math.min(max, Math.max(min, value));

export function computeGroupChildBoundaryResize({
  dir,
  dragged,
  adjacent,
  proposedBoundary,
  minimumDuration,
}: GroupChildBoundaryResizeArgs): GroupChildBoundaryResizeResult {
  const pairStart = dir === 'left' ? adjacent.start : dragged.start;
  const pairEnd = dir === 'left' ? dragged.end : adjacent.end;
  const boundary = clamp(proposedBoundary, pairStart + minimumDuration, pairEnd - minimumDuration);

  return {
    boundary,
    wasClamped: boundary !== proposedBoundary,
    dragged: dir === 'left'
      ? { start: boundary, end: dragged.end }
      : { start: dragged.start, end: boundary },
    adjacent: dir === 'left'
      ? { start: adjacent.start, end: boundary }
      : { start: boundary, end: adjacent.end },
  };
}

export function computeGroupEdgeResize({
  dir,
  initial,
  proposedBoundary,
  minimumDuration,
  minimumStart = 0,
}: GroupEdgeResizeArgs): GroupEdgeResizeResult {
  const boundary = dir === 'left'
    ? clamp(proposedBoundary, minimumStart, initial.end - minimumDuration)
    : Math.max(initial.start + minimumDuration, proposedBoundary);

  return {
    boundary,
    wasClamped: boundary !== proposedBoundary,
    start: dir === 'left' ? boundary : initial.start,
    end: dir === 'right' ? boundary : initial.end,
  };
}

import { describe, expect, it } from 'vitest';
import {
  computeGroupChildBoundaryResize,
  computeGroupEdgeResize,
} from '@/tools/video-editor/lib/resize-math';

describe('computeGroupChildBoundaryResize', () => {
  it('moves an interior right boundary symmetrically', () => {
    const result = computeGroupChildBoundaryResize({
      dir: 'right',
      dragged: { start: 1, end: 2 },
      adjacent: { start: 2, end: 3 },
      proposedBoundary: 2.3,
      minimumDuration: 0.05,
    });

    expect(result.wasClamped).toBe(false);
    expect(result.boundary).toBeCloseTo(2.3, 5);
    expect(result.dragged).toEqual({ start: 1, end: 2.3 });
    expect(result.adjacent).toEqual({ start: 2.3, end: 3 });
  });

  it('moves an interior left boundary symmetrically', () => {
    const result = computeGroupChildBoundaryResize({
      dir: 'left',
      dragged: { start: 1, end: 2 },
      adjacent: { start: 0, end: 1 },
      proposedBoundary: 1.3,
      minimumDuration: 0.05,
    });

    expect(result.wasClamped).toBe(false);
    expect(result.boundary).toBeCloseTo(1.3, 5);
    expect(result.dragged).toEqual({ start: 1.3, end: 2 });
    expect(result.adjacent).toEqual({ start: 0, end: 1.3 });
  });

  it('clamps the shared boundary so neither child drops below minimum duration', () => {
    const result = computeGroupChildBoundaryResize({
      dir: 'right',
      dragged: { start: 1, end: 2 },
      adjacent: { start: 2, end: 3 },
      proposedBoundary: 2.99,
      minimumDuration: 0.25,
    });

    expect(result.wasClamped).toBe(true);
    expect(result.boundary).toBeCloseTo(2.75, 5);
    expect(result.dragged).toEqual({ start: 1, end: 2.75 });
    expect(result.adjacent).toEqual({ start: 2.75, end: 3 });
  });
});

describe('computeGroupEdgeResize', () => {
  it('clamps the left edge at zero', () => {
    const result = computeGroupEdgeResize({
      dir: 'left',
      initial: { start: 2, end: 5 },
      proposedBoundary: -1,
      minimumDuration: 0.05,
    });

    expect(result.wasClamped).toBe(true);
    expect(result.start).toBe(0);
    expect(result.end).toBe(5);
  });

  it('enforces minimum duration on both directions', () => {
    const left = computeGroupEdgeResize({
      dir: 'left',
      initial: { start: 2, end: 5 },
      proposedBoundary: 4.99,
      minimumDuration: 0.5,
    });
    const right = computeGroupEdgeResize({
      dir: 'right',
      initial: { start: 2, end: 5 },
      proposedBoundary: 2.01,
      minimumDuration: 0.5,
    });

    expect(left.start).toBeCloseTo(4.5, 5);
    expect(left.end).toBe(5);
    expect(right.start).toBe(2);
    expect(right.end).toBeCloseTo(2.5, 5);
  });

  it('changes duration symmetrically for equivalent left and right proposals', () => {
    const left = computeGroupEdgeResize({
      dir: 'left',
      initial: { start: 10, end: 20 },
      proposedBoundary: 12,
      minimumDuration: 0.05,
    });
    const right = computeGroupEdgeResize({
      dir: 'right',
      initial: { start: 10, end: 20 },
      proposedBoundary: 18,
      minimumDuration: 0.05,
    });

    expect(left.end - left.start).toBeCloseTo(8, 5);
    expect(right.end - right.start).toBeCloseTo(8, 5);
  });
});

