    // sibling clips on the row that aren't part of the group.
    let { start, end } = computeGroupEdgeResize({
      dir: session.dir,
      initial: { start: session.groupInitialStart, end: session.groupInitialEnd },
      proposedBoundary: cursorBoundaryTime,
      minimumDuration: MIN_GROUP_RESIZE_DURATION,
