const MIN_CLIP_DURATION = 0.05;

interface ResizeStartTarget {
  action: TimelineAction;
  row: TimelineRow;
  dir: ResizeDir;
}

interface ResizeEndTarget extends ResizeStartTarget {
  start: number;
  end: number;
}

interface ResizeStartState {
  start: number;
  from: number;
  to: number;
  speed: number;
  trackKind: TrackKind;
  assetDuration?: number;
}

export interface UseClipResizeArgs {
  dataRef: React.MutableRefObject<TimelineData | null>;
  applyEdit: TimelineApplyEdit;
}

export interface UseClipResizeResult {
  onActionResizeStart: (params: ResizeStartTarget) => void;
  onActionResizeEnd: (params: ResizeEndTarget) => void;
  startGroupEdgeResize: (
    groupKey: PinnedGroupKey,
    edge: ResizeDir,
  ) => ((deltaSeconds: number) => void) | null;
}

/**
 * Ordered group member clipIds and the group's outer bounds, resolved from
 * the live rows. Returns null if the group isn't found or has no live clips.
 */
function resolveGroupMembers(
  current: TimelineData,
  groupKey: PinnedGroupKey,
): {
  trackId: string;
  orderedClipIds: string[];
  actionsById: Map<string, TimelineAction>;
  row: TimelineRow;
} | null {
  const group = current.config.pinnedShotGroups?.find(
    (g) => g.shotId === groupKey.shotId && g.trackId === groupKey.trackId,
  );
  if (!group) return null;

  const row = current.rows.find((r) => r.id === groupKey.trackId);
  if (!row) return null;

  const actionsById = new Map<string, TimelineAction>();
  for (const action of row.actions) {
    actionsById.set(action.id, action);
  }

  const orderedClipIds = orderClipIdsByAt(group.clipIds, { rows: current.rows })
    .filter((id) => actionsById.has(id));

  if (orderedClipIds.length === 0) return null;

  return { trackId: groupKey.trackId, orderedClipIds, actionsById, row };
}

/**
 * Is this resize operation an interior-boundary resize within a pinned group?
 * It is, if the clip has an adjacent live group neighbor on the drag side
 * (not the outer edge of the group).
 */
function getInteriorNeighbor(
  current: TimelineData,
  clipId: string,
  dir: ResizeDir,
): { neighborClipId: string; orderedClipIds: string[] } | null {
  const enclosing = findEnclosingPinnedGroup(current.config, clipId);
  if (!enclosing) return null;

  const orderedClipIds = orderClipIdsByAt(enclosing.group.clipIds, { rows: current.rows });
  const index = orderedClipIds.indexOf(clipId);
  if (index < 0) return null;

  const neighborIndex = dir === 'left' ? index - 1 : index + 1;
  if (neighborIndex < 0 || neighborIndex >= orderedClipIds.length) return null;

  const neighborClipId = orderedClipIds[neighborIndex];
  return { neighborClipId, orderedClipIds };
}

const getTrackKind = (
  current: TimelineData,
  rowId: string,
  fallbackTrackId?: string,
): TrackKind => {
  return current.tracks.find((track) => track.id === rowId)?.kind
    ?? current.tracks.find((track) => track.id === fallbackTrackId)?.kind
    ?? 'visual';
};

const getAssetDuration = (
  current: TimelineData,
  clipMeta: ClipMeta,
): number | undefined => {
  if (!clipMeta.asset) return undefined;
  return current.resolvedConfig.registry[clipMeta.asset]?.duration
    ?? current.registry.assets[clipMeta.asset]?.duration;
};

const getResolvedAction = (
  rows: TimelineRow[],
  rowId: string,
  actionId: string,
): TimelineAction | undefined => {
  return rows
    .find((candidate) => candidate.id === rowId)
    ?.actions.find((candidate) => candidate.id === actionId);
};

const getResizeStartState = (
  current: TimelineData,
  action: TimelineAction,
  rowId: string,
  clipMeta: ClipMeta,
): ResizeStartState => {
  const from = clipMeta.from ?? 0;
  const speed = clipMeta.speed ?? 1;
  return {
    start: action.start,
    from,
    to: getSourceTime({ from, start: action.start, speed }, action.end),
    speed,
    trackKind: getTrackKind(current, rowId, clipMeta.track),
    assetDuration: getAssetDuration(current, clipMeta),
  };
};

const mergeMetaUpdates = (
  ...patchSets: Array<Record<string, Partial<ClipMeta>>>
): Record<string, Partial<ClipMeta>> => {
  const merged: Record<string, Partial<ClipMeta>> = {};
  for (const patchSet of patchSets) {
    for (const [clipId, patch] of Object.entries(patchSet)) {
      merged[clipId] = { ...merged[clipId], ...patch };
    }
  }
  return merged;
};

/**
 * Compute a meta patch for a single clip resize. Produces only the clip's
 * own fields (hold OR from/to/speed); the caller is responsible for the
 * row-level (rows[]) update that moves the action's start/end.
 */
function computeClipResizeMetaPatch(
  clipMeta: ClipMeta,
  origin: ResizeStartState,
  newStart: number,
  newEnd: number,
  dir: ResizeDir,
): Partial<ClipMeta> {
  const resolvedDuration = newEnd - newStart;
  if (resolvedDuration <= 0) return {};

  // Hold clips: just update `hold`.
  if (typeof clipMeta.hold === 'number') {
    return { hold: resolvedDuration };
  }

  // Media clips on visual tracks: treat as speed-based resize.
  if (origin.trackKind === 'visual') {
    if (dir === 'left') {
      const from = Math.max(0, origin.from + (newStart - origin.start) * origin.speed);
      return {
        from,
        to: origin.to,
        speed: (origin.to - from) / resolvedDuration,
      };
    }
    return {
      from: origin.from,
      to: origin.to,
      speed: (origin.to - origin.from) / resolvedDuration,
    };
  }

  // Audio tracks: adjust from/to without changing speed.
  const from = Math.max(0, origin.from + (newStart - origin.start) * origin.speed);
  const unclampedTo = from + resolvedDuration * origin.speed;
  return {
    from,
    to: typeof origin.assetDuration === 'number'
      ? Math.min(origin.assetDuration, unclampedTo)
      : unclampedTo,
  };
}

/**
 * Apply a new start/end to a specific action in `rows` and return the
 * updated rows array. Pure; does not mutate input.
 */
function applyActionBounds(
  rows: TimelineRow[],
  rowId: string,
  actionId: string,
  nextStart: number,
  nextEnd: number,
): TimelineRow[] {
  return rows.map((row) => {
    if (row.id !== rowId) return row;
    return {
      ...row,
      actions: row.actions.map((action) => (
        action.id === actionId ? { ...action, start: nextStart, end: nextEnd } : action
      )),
    };
  });
}

export function useClipResize({
  dataRef,
  applyEdit,
}: UseClipResizeArgs): UseClipResizeResult {
  const resizeStartRef = useRef<Record<string, ResizeStartState>>({});
  const resizeTransactionIdRef = useRef<Record<string, string>>({});

  const onActionResizeStart = useCallback(({ action, row, dir }: ResizeStartTarget) => {
    if (action.id.startsWith('uploading-')) return;
    const current = dataRef.current;
    const clipMeta = current?.meta[action.id];
    if (!current || !clipMeta || typeof clipMeta.hold === 'number') {
      // Hold clips don't need source-time snapshots; free-clip commit path
      // computes hold directly from the new end-start. We still want a
      // transaction id for the commit so undo groups correctly.
      resizeTransactionIdRef.current[action.id] = crypto.randomUUID();
      // Capture the minimal origin for hold clips too, so interior-boundary
      // resize has the same code path.
      if (current && clipMeta) {
        resizeStartRef.current[action.id] = {
          start: action.start,
          from: 0,
          to: action.end - action.start,
          speed: 1,
          trackKind: getTrackKind(current, row.id, clipMeta.track),
        };
      }
      return;
    }

    resizeStartRef.current[action.id] = getResizeStartState(current, action, row.id, clipMeta);
    resizeTransactionIdRef.current[action.id] = crypto.randomUUID();
    // Silence unused-dir lint; dir is consumed at end-time.
    void dir;
  }, [dataRef]);

  const onActionResizeEnd = useCallback(({
    action,
    row,
    start,
    end,
    dir,
  }: ResizeEndTarget) => {
    if (action.id.startsWith('uploading-')) return;
    const current = dataRef.current;
    const clipMeta = current?.meta[action.id];
    if (!current || !clipMeta) return;

    const transactionId = resizeTransactionIdRef.current[action.id] ?? crypto.randomUUID();
    const origin = resizeStartRef.current[action.id]
      ?? getResizeStartState(current, action, row.id, clipMeta);
    const baseAction = row.actions.find((candidate) => candidate.id === action.id) ?? action;

    // Interior-boundary case: clip is inside a pinned group AND has a live
    // neighbor on the drag side. Update both the dragged clip AND the
    // neighbor so the neighbor's far edge stays fixed.
    const interior = getInteriorNeighbor(current, action.id, dir);
    if (interior) {
      const neighborAction = row.actions.find((candidate) => candidate.id === interior.neighborClipId);
      const neighborMeta = current.meta[interior.neighborClipId];
      if (neighborAction && neighborMeta) {
        const resized = computeGroupChildBoundaryResize({
          dir,
          dragged: { start: baseAction.start, end: baseAction.end },
          adjacent: { start: neighborAction.start, end: neighborAction.end },
          proposedBoundary: dir === 'left' ? start : end,
          minimumDuration: MIN_CLIP_DURATION,
        });
        const neighborDir: ResizeDir = dir === 'right' ? 'left' : 'right';
        const primaryPatch = computeClipResizeMetaPatch(
          clipMeta,
          origin,
          resized.dragged.start,
          resized.dragged.end,
          dir,
        );
        const neighborOrigin: ResizeStartState = {
          start: neighborAction.start,
          from: neighborMeta.from ?? 0,
          to: getSourceTime(
            { from: neighborMeta.from ?? 0, start: neighborAction.start, speed: neighborMeta.speed ?? 1 },
            neighborAction.end,
          ),
          speed: neighborMeta.speed ?? 1,
          trackKind: getTrackKind(current, row.id, neighborMeta.track),
          assetDuration: getAssetDuration(current, neighborMeta),
        };
        const neighborPatch = computeClipResizeMetaPatch(
          neighborMeta,
          neighborOrigin,
          resized.adjacent.start,
          resized.adjacent.end,
          neighborDir,
        );

        let nextRows = applyActionBounds(
          current.rows,
          row.id,
          action.id,
          resized.dragged.start,
          resized.dragged.end,
        );
        nextRows = applyActionBounds(
          nextRows,
          row.id,
          interior.neighborClipId,
          resized.adjacent.start,
          resized.adjacent.end,
        );

        const metaUpdates: Record<string, Partial<ClipMeta>> = {
