      return;
    }

    if (session.context.kind === 'outer') {
      const nextRows = applyActionUpdates(current.rows, session.rowId, updates);
      const perClipMetaUpdates: Record<string, Partial<ClipMeta>> = {};
      for (const update of updates) {
