              proposedBoundary: resizeParams.dir === 'left' ? resizeParams.start : resizeParams.end,
              minimumDuration: MIN_GROUP_RESIZE_DURATION,
            });

            return applyRowUpdates(currentRows, resizeParams.row.id, {
              [resizeParams.action.id]: resized.dragged,
              [adjacentActionId]: resized.adjacent,
            });
          });
