                const timelineAction = targetRow.actions.find((candidate) => candidate.id === clipId);
                if (!timelineAction) {
                  throw new Error(`expected action ${clipId}`);
                }
                return timelineAction;
              });
              const firstAction = groupActions[0];
              const lastAction = groupActions[groupActions.length - 1];
              if (!firstAction || !lastAction) {
                return currentRows;
              }

              const groupInitial = {
                start: Math.min(...groupActions.map((timelineAction) => timelineAction.start)),
                end: Math.max(...groupActions.map((timelineAction) => timelineAction.end)),
              };
              const resized = computeGroupEdgeResize({
                dir: edge,
                initial: groupInitial,
                proposedBoundary: edge === 'left'
