const handleScroll = (event: UIEvent<HTMLDivElement>) => {
  const nextMetrics = {
    scrollLeft: event.currentTarget.scrollLeft,
    scrollTop: event.currentTarget.scrollTop,
  };

  scrollMetricsRef.current = nextMetrics;
  if (nextMetrics.scrollLeft !== scrollLeft) {
