/bin/zsh -lc "node - <<'NODE'
const {execSync} = require('child_process');
const fs = require('fs');
const path = 'src/tools/video-editor/components/TimelineEditor/TimelineCanvas.tsx';
const current = fs.readFileSync(path, 'utf8');
const head = execSync("'`git show HEAD:${path}`, {encoding:'"'utf8'});
const names = ['updateResize','endResize','handleResizePointerDown'];
function extract(src, name){
  const start = src.indexOf("'`const ${name} = useCallback(`);
  if (start === -1) return null;
  const tail = src.slice(start);
  const nextMatches = names.filter((n)=>n!==name).map((n)=>tail.indexOf(`const ${n} = useCallback(`)).filter((i)=>i>0);
  const next = nextMatches.length ? Math.min(...nextMatches) : tail.length;
  return tail.slice(0, next).trimEnd();
}
let currentTotal = 0;
let headTotal = 0;
for (const name of names) {
  const c = extract(current, name);
  const h = extract(head, name);
  const cLines = c ? c.split('"'\\n').length : 0;
  const hLines = h ? h.split('\\n').length : 0;
  currentTotal += cLines;
  headTotal += hLines;
  console.log("'`${name}: HEAD=${hLines} CURRENT=${cLines}`);
}
console.log(`TOTAL: HEAD=${headTotal} CURRENT=${currentTotal}`);
NODE'

